// 콘텐츠 확보 계획
const BOOK_PLAN = [
  { category: '개발', level: '입문', topic: '1인 개발자의 SaaS 런칭 가이드', keywords: 'SaaS, 솔로 창업, 제품 출시, MVP' },
  { category: '개발', level: '실무', topic: 'Next.js 풀스택 실무', keywords: 'Next.js, React, 풀스택, 웹개발' },
  { category: '개발', level: '실무', topic: 'Supabase로 빠른 백엔드 구축', keywords: 'Supabase, PostgreSQL, 백엔드, API' },
  { category: '개발', level: '심화', topic: 'API 설계와 운영의 기술', keywords: 'REST API, OpenAPI, 설계, 운영' },
  { category: '개발', level: '실무', topic: '서버리스 아키텍처 입문', keywords: '서버리스, Lambda, Vercel, 배포' },
  { category: '개발', level: '실무', topic: '스타트업 개발팀 운영법', keywords: 'CTO, 팀 관리, 코드 리뷰, 애자일' },
  { category: '마케팅', level: '입문', topic: '1인 스타트업 그로스 해킹', keywords: '그로스해킹, 사용자 획득, 바이럴, 퍼널' },
  { category: '마케팅', level: '실무', topic: '콘텐츠 마케팅 실전 전략', keywords: '콘텐츠마케팅, 블로그, 유튜브, 뉴스레터' },
  { category: '마케팅', level: '실무', topic: 'SEO 완전정복 (한국 시장)', keywords: 'SEO, 검색엔진, 네이버, 구글' },
  { category: '마케팅', level: '심화', topic: '제품 주도 성장 (PLG) 입문', keywords: 'PLG, 제품주도성장, 온보딩, 활성화' },
  { category: '마케팅', level: '입문', topic: '린 스타트업 마케팅 실전', keywords: '린스타트업, MVP, 고객 검증, 피봇' },
  { category: '세무/법무', level: '입문', topic: '1인 사업자 세금 완전 정복', keywords: '종합소득세, 부가가치세, 경비처리, 절세' },
  { category: '세무/법무', level: '실무', topic: '스타트업 계약서 핵심 정리', keywords: '계약서, 근로계약, 투자계약, NDA' },
  { category: '세무/법무', level: '입문', topic: '개인사업자 vs 법인 설립 가이드', keywords: '법인설립, 개인사업자, 세금, 책임' },
  { category: '세무/법무', level: '입문', topic: '지식재산권과 특허 입문', keywords: '특허, 상표, 저작권, IP 전략' },
  { category: '세무/법무', level: '심화', topic: '스타트업 투자계약 이해하기', keywords: 'VC, 텀시트, 지분희석, 우선주' },
  { category: '디자인', level: '입문', topic: '1인 창업자를 위한 UX 디자인', keywords: 'UX, 사용자경험, 와이어프레임, 프로토타입' },
  { category: '디자인', level: '실무', topic: 'Figma 실무 마스터', keywords: 'Figma, UI 디자인, 컴포넌트, 오토레이아웃' },
  { category: '디자인', level: '실무', topic: '브랜드 아이덴티티 만들기', keywords: '브랜딩, 로고, 컬러시스템, 타이포그래피' },
  { category: '디자인', level: '입문', topic: '랜딩 페이지 전환율 극대화', keywords: '랜딩페이지, CTA, A/B테스트, 전환율' },
  { category: 'AI', level: '실무', topic: 'Cursor AI로 빠른 개발하기', keywords: 'Cursor, AI 코딩, 코드 생성, 생산성' },
  { category: 'AI', level: '실무', topic: 'Make(Integromat) 자동화 입문', keywords: 'Make, 자동화, 노코드, 워크플로우' },
  { category: 'AI', level: '심화', topic: 'RAG 기반 AI 챗봇 구축하기', keywords: 'RAG, LLM, 벡터DB, 챗봇' },
  { category: 'HRD', level: '실무', topic: 'AI 시대의 팀 역량 강화 전략', keywords: 'HRD, 직무교육, AI 리터러시, 조직학습' }
];

const existingCount = $input.all().length;
const nextIndex = Math.max(0, existingCount - 6) % BOOK_PLAN.length;
const plan = BOOK_PLAN[nextIndex] || BOOK_PLAN[0];

const nextId = existingCount + 1;
const nextSlug = 'b' + nextId;
const variants = ['a', 'b', 'c', 'd', 'e'];
const coverVariant = variants[nextId % variants.length];
const priceMap = { '입문': 17000, '실무': 19000, '심화': 27000 };
const price = priceMap[plan.level] || 19000;
const today = new Date();
const dateStr = today.toISOString().split('T')[0];

return [{ json: { plan, nextSlug, nextId, coverVariant, price, dateStr, existingCount } }];

// Gemini 응답 파싱 (2.5 Flash thinking 모델 대응)
const aiResponse = $input.first().json;
const parts = (aiResponse.candidates?.[0]?.content?.parts) || [];
const responsePart = parts.find(p => !p.thought) || parts[parts.length - 1] || {};
const rawText = responsePart.text || '';

let bookData;
try {
  bookData = JSON.parse(rawText);
} catch(e) {
  const blockMatch = rawText.match(/```(?:json)?\s*([\s\S]*?)```/);
  const objMatch = rawText.match(/\{[\s\S]*\}/);
  const extracted = blockMatch ? blockMatch[1].trim() : (objMatch ? objMatch[0] : null);
  try {
    bookData = JSON.parse(extracted || '{}');
  } catch(e2) {
    bookData = {};
  }
}
if (!bookData || typeof bookData !== 'object') bookData = {};
bookData.title = bookData.title || '파싱 오류';
bookData.author = bookData.author || '미상';
bookData.description = bookData.description || '';
bookData.toc = Array.isArray(bookData.toc) ? bookData.toc : [];
bookData.sample_chapter = bookData.sample_chapter || '';
bookData.pages = Number(bookData.pages) || 200;
bookData.tags = Array.isArray(bookData.tags) ? bookData.tags : [];

const meta = $('다음 생성 도서 결정').first().json;

const tocText = (bookData.toc || []).map((ch, i) => (i+1) + '. ' + ch).join('\n');
const markdownContent = [
  '# ' + bookData.title,
  '',
  '**저자**: ' + bookData.author,
  '**카테고리**: ' + meta.plan.category,
  '**난이도**: ' + meta.plan.level,
  '**페이지**: ' + bookData.pages + 'p',
  '**가격**: ' + meta.price.toLocaleString('ko-KR') + '원',
  '**슬러그**: ' + meta.nextSlug,
  '**생성일**: ' + meta.dateStr,
  '**태그**: ' + (bookData.tags || []).join(', '),
  '',
  '---',
  '',
  '## 도서 소개',
  '',
  bookData.description || '',
  '',
  '---',
  '',
  '## 목차',
  '',
  tocText,
  '',
  '---',
  '',
  '## 샘플 챕터',
  '',
  bookData.sample_chapter || ''
].join('\n');

const base64Content = btoa(unescape(encodeURIComponent(markdownContent)));
const safeName = (bookData.title || 'book').replace(/[^가-힣a-zA-Z0-9]/g, '_');
const fileName = meta.nextSlug + '_' + safeName + '.md';

const supabasePayload = {
  slug: meta.nextSlug,
  title: bookData.title,
  author: bookData.author,
  price_krw: meta.price,
  cover_variant: meta.coverVariant,
  pages: Number(bookData.pages) || 200,
  level: meta.plan.level,
  category_id: meta.plan.category,
  tags: bookData.tags || [],
  description: bookData.description || '',
  toc: (bookData.toc || []).join('\n'),
  is_new: true,
  published_at: new Date().toISOString(),
  rating: 0,
  review_count: 0
};

return [{ json: { bookData, meta, base64Content, fileName, supabasePayload } }];

const githubResult = $('GitHub - 06.콘텐츠 폴더에 파일 저장').first().json;
const supabaseItems = $('Supabase - 신규 도서 DB 등록').all();
const supabaseResult = supabaseItems.length > 0 ? supabaseItems[0].json : null;
const meta = $('콘텐츠 파싱 & 파일 준비').first().json;

const githubOk = !!(githubResult && githubResult.content && githubResult.content.name);
const supabaseOk = !!(Array.isArray(supabaseResult) ? supabaseResult[0] : supabaseResult && supabaseResult.id);

return [{ json: {
  success: githubOk && supabaseOk,
  book_title: meta.bookData.title,
  slug: meta.meta.nextSlug,
  category: meta.meta.plan.category,
  level: meta.meta.plan.level,
  price: meta.meta.price,
  github_ok: githubOk,
  github_url: githubOk ? githubResult.content.html_url : '',
  supabase_ok: supabaseOk,
  supabase_id: Array.isArray(supabaseResult) ? (supabaseResult[0] && supabaseResult[0].id) : (supabaseResult && supabaseResult.id),
  site_url: 'https://rodi-book4.vercel.app/books/' + meta.meta.nextSlug,
  generated_at: new Date().toISOString()
} }];
